class Solution:
    def search(self, nums: list[int], target: int) -> int:
        if not nums:
            return -1
        left = 0
        right = len(nums) - 1
        while left <= right:
            mid = left + (right - left) // 2
            if nums[mid] == target:
                return mid
            if nums[left] <= target < nums[right] or (nums[left] > target > nums[right] and nums[mid] <= target):
                left = mid + 1
            else:
                right = mid - 1
        return -1

# main function
